import { createTool } from "@mastra/core/tools";
import { z } from "zod";

/**
 * Preferences Tool - Manages user preferences for link destinations
 * Stores preferences in database per user
 */

export const preferencesTool = createTool({
  id: "preferences-tool",
  description: "Manages user preferences for external link destinations (Kraken vs CoinGecko/Yahoo Finance).",

  inputSchema: z.object({
    action: z.enum(['set', 'get']).describe("Action to perform on preferences"),
    linkPreference: z.enum(['default', 'kraken']).optional().describe("Link preference: 'default' (CoinGecko/Yahoo) or 'kraken'"),
    userId: z.string().optional().describe("User ID for personalized storage"),
  }),

  outputSchema: z.object({
    success: z.boolean(),
    linkPreference: z.string(),
    message: z.string(),
  }),

  execute: async ({ context, mastra, runtimeContext }) => {
    const logger = mastra?.getLogger();
    logger?.info('🔧 [PreferencesTool] Starting execution', { action: context.action });

    // Get userId from context
    const userId = context.userId || (runtimeContext as any)?.resourceId || 'default-user';
    const PREFS_KEY = `user_preferences_${userId}`;

    logger?.info('📝 [PreferencesTool] User context', { userId, prefsKey: PREFS_KEY });

    try {
      // Get current preferences from memory storage (PostgreSQL-backed)
      let currentPref = 'default'; // Default to CoinGecko/Yahoo Finance
      
      try {
        const memory = mastra?.memory;
        if (memory) {
          const messages = await memory.getMessages({
            resourceId: userId,
            threadId: PREFS_KEY,
          });
          
          if (messages && messages.length > 0) {
            const lastMessage = messages[messages.length - 1];
            if (lastMessage.content) {
              const prefs = JSON.parse(lastMessage.content as string);
              currentPref = prefs.linkPreference || 'default';
            }
          }
        }
      } catch (e) {
        logger?.info('[PreferencesTool] No existing preferences found, using defaults');
        currentPref = 'default';
      }

      let message = '';
      let success = true;

      if (context.action === 'set' && context.linkPreference) {
        currentPref = context.linkPreference;
        
        // Save updated preferences to memory
        const memory = mastra?.memory;
        if (memory) {
          await memory.saveMessages({
            messages: [{
              role: 'assistant',
              content: JSON.stringify({ linkPreference: currentPref }),
            }],
            resourceId: userId,
            threadId: PREFS_KEY,
          });
          logger?.info('💾 [PreferencesTool] Preferences saved', { userId, linkPreference: currentPref });
        }

        message = currentPref === 'kraken' 
          ? '✅ Links set to Kraken (crypto & stocks will link to kraken.com)'
          : '✅ Links set to default (crypto→CoinGecko, stocks→Yahoo Finance)';
      } else {
        message = currentPref === 'kraken'
          ? 'Current link preference: Kraken'
          : 'Current link preference: Default (CoinGecko/Yahoo Finance)';
      }

      logger?.info('✅ [PreferencesTool] Action completed', { 
        action: context.action,
        userId,
        linkPreference: currentPref
      });

      return {
        success,
        linkPreference: currentPref,
        message,
      };
    } catch (error: any) {
      logger?.error('❌ [PreferencesTool] Error', { error: error.message });
      throw new Error(`Preferences operation failed: ${error.message}`);
    }
  },
});
